using UnityEngine;
using Climbing;

public class FlyingInspectorFinal
{
    public static string Inspect()
    {
        GameObject pm = GameObject.Find("Player_New/PlayerModel");
        if (pm == null) return "Player_New/PlayerModel not found";

        Rigidbody rb = pm.GetComponent<Rigidbody>();
        ThirdPersonController tpc = pm.GetComponent<ThirdPersonController>();
        MovementCharacterController mcc = pm.GetComponent<MovementCharacterController>();
        ClimbController cc = pm.GetComponent<ClimbController>();

        string report = $"--- Player Inspection ({pm.name}) ---\n";

        if (rb != null) {
            report += $"Rigidbody: Gravity={rb.useGravity}, Kinematic={rb.isKinematic}, Constraints={rb.constraints}\n";
        }

        if (tpc != null) {
            report += $"TPC: isGrounded={tpc.isGrounded}, onAir={tpc.onAir}, allowMovement={tpc.allowMovement}, isJumping={tpc.isJumping}\n";
        }

        if (cc != null) {
            // Accessing private field via reflection since we can't see it directly
            var field = typeof(ClimbController).GetField("curClimbState", System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance);
            object state = field != null ? field.GetValue(cc) : "Unknown";
            report += $"ClimbController: State={state}\n";
        }

        report += $"Position: {pm.transform.position}\n";

        // Check if there is anything below
        RaycastHit hit;
        if (Physics.Raycast(pm.transform.position + Vector3.up * 0.1f, Vector3.down, out hit, 100f)) {
            report += $"Ground check: Found {hit.collider.name} at distance {hit.distance}\n";
        } else {
            report += "Ground check: Nothing found below for 100 units!\n";
        }

        return report;
    }
}
